// Saga compensation panel — pending compensations + manual trigger.
// Generated by flowforge JTBD generator — do not edit by hand.
import * as React from "react";

import { adminApi, type AdminSagaStep } from "../api";
import { ADMIN_PERMISSIONS_BY_JTBD, type AdminJtbdId } from "../permissions";

export interface SagaPanelProps {
	/** Operator's granted permissions, supplied by the auth proxy. */
	grantedPermissions?: ReadonlyArray<string>;
}

function canCompensate(
	jtbdId: string,
	granted: ReadonlyArray<string>,
): boolean {
	if (!(jtbdId in ADMIN_PERMISSIONS_BY_JTBD)) return false;
	const perms = ADMIN_PERMISSIONS_BY_JTBD[jtbdId as AdminJtbdId];
	return perms.some(
		(p) => p.endsWith(".compensate") && granted.includes(p),
	);
}

export function SagaPanel(props: SagaPanelProps): React.ReactElement {
	const granted: ReadonlyArray<string> = props.grantedPermissions ?? [];
	const [rows, setRows] = React.useState<ReadonlyArray<AdminSagaStep>>([]);
	const [error, setError] = React.useState<string | null>(null);
	const [busy, setBusy] = React.useState(false);
	const [triggering, setTriggering] = React.useState<string | null>(null);

	const load = React.useCallback(async () => {
		setBusy(true);
		setError(null);
		try {
			setRows(await adminApi.listPendingSagas());
		} catch (e: unknown) {
			setError(e instanceof Error ? e.message : "load failed");
		} finally {
			setBusy(false);
		}
	}, []);

	React.useEffect(() => {
		void load();
	}, [load]);

	const compensate = React.useCallback(
		async (sagaId: string) => {
			setTriggering(sagaId);
			setError(null);
			try {
				await adminApi.compensateSaga(sagaId);
				await load();
			} catch (e: unknown) {
				setError(e instanceof Error ? e.message : "compensate failed");
			} finally {
				setTriggering(null);
			}
		},
		[load],
	);

	return (
		<section aria-labelledby="saga-heading">
			<h2 id="saga-heading">Saga compensations</h2>
			<p className="ff-admin-hint">
				Pending compensations recorded by the engine's saga ledger. The per-saga
				span list is empty until the OTel adapter (item 12) ships — the panel
				will display "no spans recorded" for entries created before that.
			</p>
			{error ? (
				<p role="alert" className="ff-admin-error">
					{error}
				</p>
			) : null}
			<table className="ff-admin-table">
				<thead>
					<tr>
						<th scope="col">saga</th>
						<th scope="col">JTBD</th>
						<th scope="col">step</th>
						<th scope="col">status</th>
						<th scope="col">created</th>
						<th scope="col">spans</th>
						<th scope="col">action</th>
					</tr>
				</thead>
				<tbody>
					{rows.map((row) => {
						const allowed = canCompensate(row.jtbd_id, granted);
						return (
							<tr key={row.id}>
								<td>
									<code>{row.saga_id}</code>
								</td>
								<td>{row.jtbd_id}</td>
								<td>
									<code>{row.step}</code>
								</td>
								<td>
									<span className={`ff-admin-status ff-admin-status-${row.status}`}>
										{row.status}
									</span>
								</td>
								<td>
									<time dateTime={row.created_at}>{row.created_at}</time>
								</td>
								<td>
									<em className="ff-admin-muted">no spans recorded</em>
								</td>
								<td>
									<button
										type="button"
										disabled={!allowed || triggering === row.saga_id || busy}
										onClick={() => void compensate(row.saga_id)}
										title={
											allowed
												? "Trigger compensation"
												: "Missing admin.<jtbd>.compensate permission"
										}
									>
										{triggering === row.saga_id ? "Compensating…" : "Compensate"}
									</button>
								</td>
							</tr>
						);
					})}
					{rows.length === 0 && !busy ? (
						<tr>
							<td colSpan={7}>no pending compensations</td>
						</tr>
					) : null}
				</tbody>
			</table>
		</section>
	);
}
